/**
 * CodeContext - typed context object passed to every runTypescript code action.
 *
 * Operators MUST annotate execute() as: `function execute(context: CodeContext)`.
 * The TypeScriptValidator rejects any execute() with an untyped first parameter.
 *
 * Trigger payloads and prior step outputs are NOT directly reachable; declare
 * each value via the action`s `inputData` prop using `{{trigger.data.X}}` /
 * `{{steps.Y.Z}}` template references. `actions` references reusable templates
 * at app.actions[] — call by name with input vars.
 */
export interface CodeContext {
  /** Template-resolved key-value pairs declared in the action`s inputData prop */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly inputData: Record<string, any>
  /** Two-shape callable surface: actions.ref(<template>, vars) or actions.<type>.<op>(props) */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly actions: {
    readonly ref: (templateName: string, vars?: Record<string, unknown>) => Promise<any>
  } & Record<string, Record<string, (props?: Record<string, unknown>) => Promise<any>>>
  /** Environment variables (values redacted in logs when length >= 8) */
  readonly env: Record<string, string>
  /** Structured logging — info/warn/error */
  readonly log: {
    readonly info: (...args: ReadonlyArray<unknown>) => void
    readonly warn: (...args: ReadonlyArray<unknown>) => void
    readonly error: (...args: ReadonlyArray<unknown>) => void
  }
  /** Declared npm packages, keyed by package name (e.g. packages.lodash) */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly packages: Record<string, any>
}

/**
 * Identity function that provides TypeScript autocompletion for Sovrium app configs.
 *
 * @example
 * ```typescript
 * import { defineConfig } from '@sovrium/types'
 *
 * export default defineConfig({
 *   name: 'my-app',
 *   description: 'My application',
 * })
 * ```
 */
export declare const defineConfig: <T extends AppConfig>(config: T) => T
